module UART_Controller (  
    input wire clk,  
    input wire reset,  
    input wire transmit_enable,  
    input wire [7:0] data_in,  
    output reg tx  
);  
    reg [3:0] bit_counter;  
    reg [7:0] shift_reg;  
    reg transmitting;  

    always @(posedge clk or posedge reset) begin  
        if (reset) begin  
            tx <= 1;  
            bit_counter <= 0;  
            shift_reg <= 0;  
            transmitting <= 0;  
        end else begin  
            if (transmit_enable && !transmitting) begin  
                shift_reg <= data_in;  
                bit_counter <= 0;  
                transmitting <= 1;  
                tx <= 0; // Start bit  
            end else if (transmitting) begin  
                if (bit_counter < 8) begin  
                    tx <= shift_reg[bit_counter];  
                    bit_counter <= bit_counter + 1;  
                end else begin  
                    tx <= 1; // Stop bit  
                    transmitting <= 0;  
                end  
            end  
        end  
    end  
endmodule
